updated = 0
skipped = 0
for b in books:
    bid = b['id']
    if bid in descriptions:
        if not b.get('description'):
            b['description'] = descriptions[bid]
            updated += 1
        else:
            skipped += 1

with open('/root/books/webapp/books.json', 'w', encoding='utf-8') as f:
    json.dump(books, f, ensure_ascii=False, separators=(',', ':'))

print(f'Добавлено описаний: {updated}, пропущено (уже есть): {skipped}. Done.')
